SELECT total_population
FROM state_population
WHERE year = 2022 AND state_id = 1;

SELECT state_id
FROM health_indicators
WHERE life_expectancy = (SELECT MAX(life_expectancy) FROM health_indicators);

SELECT state_id, unemployment_rate
FROM state_economic_data
WHERE year = 2022;

SELECT state_id, gdp, poverty_rate
FROM state_economic_data
ORDER BY gdp DESC;

SELECT AVG(life_expectancy) AS average_life_expectancy
FROM health_indicators
WHERE year = (SELECT MAX(year) FROM health_indicators);
